import axios from "axios";


// ==========================================
// CREATE AXIOS INSTANCE
// ==========================================

const API = axios.create({

  baseURL: "http://localhost:5000/api",

  headers: {

    "Content-Type": "application/json",

  },

});



// ==========================================
// REQUEST INTERCEPTOR
// Automatically attach token
// ==========================================

API.interceptors.request.use(

  (config) => {

    const token = localStorage.getItem("token");

    if (token) {

      config.headers.Authorization = `Bearer ${token}`;

    }

    return config;

  },

  (error) => {

    return Promise.reject(error);

  }

);



// ==========================================
// RESPONSE INTERCEPTOR
// Handle token expire
// ==========================================

API.interceptors.response.use(

  (response) => {

    return response;

  },

  (error) => {

    if (

      error.response &&

      error.response.status === 401

    ) {

      alert("Session Expired. Please Login Again");

      localStorage.removeItem("token");

      window.location.href = "/login";

    }

    return Promise.reject(error);

  }

);



// ==========================================
// AUTH API
// ==========================================

export const registerUser = (userData) =>

  API.post("/auth/register", userData);



export const loginUser = (userData) =>

  API.post("/auth/login", userData);



// ==========================================
// USER API
// ==========================================

export const getAllUsers = () =>

  API.get("/users");



export const getFreelancers = () =>

  API.get("/users/freelancers");



export const getClients = () =>

  API.get("/users/clients");



// ==========================================
// PROJECT API
// ==========================================

export const createProject = (projectData) =>

  API.post("/projects", projectData);



export const getAllProjects = () =>

  API.get("/projects");



export const getClientProjects = (clientId) =>

  API.get(`/projects/client/${clientId}`);



// ==========================================
// PROPOSAL API
// ==========================================

export const sendProposal = (proposalData) =>

  API.post("/proposals", proposalData);



export const getProjectProposals = (projectId) =>

  API.get(`/proposals/project/${projectId}`);



export const getFreelancerProposals = (freelancerId) =>

  API.get(`/proposals/freelancer/${freelancerId}`);



// ==========================================
// ADMIN API
// ==========================================

export const getAdminDashboard = () =>

  API.get("/admin/dashboard");



// ==========================================
// EXPORT DEFAULT
// ==========================================

export default API;
